#include<bits/stdc++.h>
using namespace std;

int a[100005]; 

int main()
{
	int flag,n,i;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	for(int i=1;i<=n;i++)
	{
		if(a[i]==2)
		{
			printf("2 ");
			continue; 
		}
			flag=0;
			for(int j=2;j<=a[i]-1;j++)
			{
				if(a[i]%j!=0)
				{
					flag=1;
				}
				else
				{
					flag=0;
					break;
				}
			}
			if(flag==1)
			{
				printf("%d ",a[i]);
			}
	}
	return 0;
}
